import{_ as c}from"./nyalra_kb-7135827b.js";import{_ as l}from"./nyalra_no_mono-8344e451.js";import{_ as r,W as i,X as s,Y as _,Z as e,$ as t,a1 as a,a2 as f,a0 as g,C as o}from"./framework-91490e6a.js";const m={},d=e("figure",null,[e("img",{src:c,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),u={href:"https://tree-novel.com/works/episode/c5ac8251d1c5bfe8d7467eac83e8e736.html",target:"_blank",rel:"noopener noreferrer"},b=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),h=g('<hr><figure><img src="https://img.tree-novel.com/talk/f4988f3f854caf890b10c7ebf71baf1a.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>这篇文章刊登的时候，可能已经过去一个多月了，但我大约一个星期前独自一人踏上了旅程。我觉得如果一直呆在自己的房间里，精神也会变得孤僻，所以我决定外出旅行，希望能带来一些积极的变化。</p><p>我漫无目的地乘上了新干线，在名古屋下车。当然，在名古屋也没有什么特别的计划，只是去了一家商务酒店。在大堂里，有许多外国游客在谈笑风生，兴高采烈地讨论着他们的日本之行。他们肯定是和朋友一起度过了愉快的旅程。可能会遇到一些小麻烦，但那也将成为宝贵的经验。</p><p>第二天，前往岐阜。前一晚我只是在酒店过夜，所以我的独自一人旅行终于开始了。我尽量避免去「The·旅游胜地」，而是选择去一些乡村小镇漫游，参观一些不太知名的复古景点等等。原因是，我出生在冲绳，距离热门旅游区域很近，所以我理解「游客不知为何都想来这里，但对于当地人来说并不好玩」的感觉。</p><p>比如说，海。前来冲绳的外地人必会寻求大海。然后他们在盛夏时前往热门海滩，结果海滩总是人满为患。尽管我是冲绳人，但我却几乎看不到当地人在那些海滩上。因为没办法，当地的孩子们通常会去一些更加隐蔽的小渔村等地游泳。但这也非常有趣。与海滩不同，你可以尽情跳水玩耍，而且更重要的是，人不多。在冲绳，即使是冬天也会有很多人穿着短袖。而且，旅游区附近的商店通常会高价收费。我在高中时曾在旅游区的居酒屋打工，常常想，为什么人们在旅行时会因为心情好而愿意花这么多钱去品尝冲绳料理呢？如果是当地人，他们肯定会去别的地方。</p><p>因为已经养成了这种意识，所以我认为某个县市真正的魅力不在于旅游胜地，所以我决定尽量游览一些不太知名的地方。这正是独自一人旅行的乐趣所在。</p><p>比如，岐阜复古博物馆。这个充满昭和风情的乡村乐园位于深山，当地的大叔们在那里打老虎机打发时间。这正是我想要看到的景象。</p><figure><img src="https://img.tree-novel.com/talk/a174401042d1887e23c683cb62dd712c.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>之后有一段时间，我逛了逛那种景点（我喜欢乡下大商场里的游戏中心的独特氛围），最后果然还是想看看旅游胜地，我决定从名古屋乘船前往一个旅游区。结果，这次真是大失败，大失败！整个岛上都挤满了情侣。</p><figure><img src="https://img.tree-novel.com/talk/3b4eb9a3b165d9418e5e019c7a86161c.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>例如，这个秋千，「看起来像是涩涩游戏中的CG！」 我也想去拍照，但显然，这个秋千是为情侣设计的，需要两个人一起摇，于是有好多情侣在那里排队等候。只有我一个人傻傻地站在那里。大家都在好奇地看着我，想知道：「这个人是谁……？」一个宅男独自来秋千是干什么的呢？这让我感到很沮丧。</p><p>我自己一个人荡了秋千，然后去海边，当然，那里也是情侣成群结队。他们在公众面前拥抱，这让我感到很尴尬。我觉得这实在是看不下去了！但这只是因为我因孤独而嫉妒，两个人一起来海边玩是理所当然的。事实上，独自一人来到这个岛屿才更令人害怕。是不是有犯罪目的？</p><p>旅馆也是，更像是以情侣和夫妻一起住为前提，所以房间里有两张床。费用也是两个人的费用。餐点也是两个人份。周围都是情侣和夫妻在欢声笑语中品尝当地美食，而我默默地吃着自己的餐点。此外，旁边的座位也摆满了食物，看到这一幕，一位大叔笑着说：「这个家伙是不是因为失恋而一个人来的？”」这让我感到特别难过。然后，我强迫自己吃了两份食物，尽管我吃得很少。</p><p>最后，我实在忍不住，回到房间里吐了出来。然后，我感到身体非常不适，躺在两张并排的床上。起初我并不在意，但当别人关心我时，我突然感到自己像是一个在旅行前被甩了的可怜家伙。为什么我非得感受到失去恋人的痛苦呢？</p><p>对我来说，游览旅游景点还是太早了。人们在与他人在一起时才会真正感到孤独。当我朝窗外看去，只看到一大群情侣时，我感到特别孤独。我并不会嫉妒那些拥有伴侣的人，但旅行本来是为了填补寂寞，却反而增加了寂寞感。这已经不言自明了。</p><p>这段经历让我更加理解了一人旅行和孤独之间的微妙关系。虽然独自旅行可以让你自由自在地决定去哪里，但也会让你在某些时刻感到孤独。然而，这也是一种学习和成长的机会，可以帮助你更好地理解自己，尤其是在与他人相比较时。旅行中的种种经历，无论是愉快的还是寂寞的，都可以成为宝贵的回忆和教训。</p><hr><p><img src="'+l+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/5019dcf05a6615b43d5f569c8da3bc86.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【绮丽的玻璃珠】这是我在旅行目的地的艺术展上购买的一颗美丽的玻璃珠，里面封存了一片蓝色透明的世界。当我询问后，听说这是一位年轻的男性创作者的作品。在旅行中收集这样的「美」的物品，让我感到自己似乎渐渐变得更加成熟了。</p></blockquote>',20);function k(x,y){const n=o("ExternalLinkIcon"),p=o("RouterLink");return i(),s("div",null,[_(" more "),d,e("p",null,[t("原文链接："),e("a",u,[t("第21回／一人旅と孤独"),a(n)])]),e("blockquote",null,[b,e("p",null,[a(p,{to:"/posts/Translate/nyalra_kb_20.html"},{default:f(()=>[t("【奈亚拉面壁自语】第20回｜深夜的例行检查之战【230404】")]),_:1})])]),h])}const C=r(m,[["render",k],["__file","nyalra_kb_21.html.vue"]]);export{C as default};
